+                is_source: false,
+                columns: vec![col],
+                coefficients: vec![Gf256::ONE],
+                data: vec![0u8; symbol_size],
+            });
+        }
+
+        let result = decoder.decode(&received).unwrap();
+
+        // At least some peeling should occur
+        assert!(result.stats.peeled > 0, "expected some peeling");
+    }
+}

